B.Oa=new A.F(B.j,["Oct 2024 - Present","Okt. 2024 \u2013 Heute"],t.w)
B.Ou=new A.F(B.j,[u.R,"Freiberuflicher DevSecOps- & KI-Automatisierungs-Engineer"],t.w)
B.NP=new A.F(B.j,[u.a9,"Selbstst\xe4ndig, Bochum, Deutschland. Ich konzipiere produktionsreife Kubernetes-Infrastruktur, GitOps-Workflows und LLM-gest\xfctzte Automatisierung f\xfcr Kunden in ganz Deutschland."],t.w)
B.OQ=new A.F(B.j,[u.I,"Ich habe produktionsreife Kubernetes-Cluster (Hetzner Cloud) mit Terraform (IaC) und ArgoCD (GitOps) entworfen und ausgerollt \u2013 mit 100 % Reproduzierbarkeit der Umgebungen und einer Reduktion der Bereitstellungszeit von 4 Tagen auf 45 Minuten (95 % Verbesserung)."],t.w)
B.Ng=new A.F(B.j,[u.W,"Ich habe automatisierte GitLab-CI/CD-Pipelines und GitOps-Workflows umgesetzt sowie eine Full-Stack-Monitoring-L\xf6sung mit Prometheus und Grafana etabliert, die die Mean Time to Detection durch proaktives Alerting und Log-Aggregation um 40 % gesenkt hat."],t.w)
B.Nr=new A.F(B.j,[u.y,"Ich habe eine souver\xe4ne, Linux-basierte Infrastruktur f\xfcr ein Immobilienportfolio mit \xfcber 700 Einheiten konzipiert und mehr als 15 Legacy-Dienste auf selbst gehostete Open-Source-Alternativen migriert \u2013 mit einer j\xe4hrlichen OPEX-Einsparung von 20.000 \u20ac an Lizenzkosten."],t.w)
B.O1=new A.F(B.j,[u.v,"Ich habe einen LLM-gest\xfctzten Automatisierungsdienst (FastAPI, RAG) f\xfcr intent-basierte E-Mail-Verarbeitung entwickelt \u2013 mit 80 % h\xf6herem Durchsatz bei gleichbleibender Genauigkeit von 95 % und einer Ersparnis von rund 8 Personenstunden pro Woche im manuellen Triage-Prozess."],t.w)
B.OU=new A.F(B.j,[u.h,"Ich habe eine geh\xe4rtete Container-Umgebung auf Basis von rootless Podman/Docker aufgebaut, CIS-konforme Security-Policies sowie automatisierte Off-Site-Backups umgesetzt und damit 99,6 % Verf\xfcgbarkeit und volle DSGVO-Konformit\xe4t f\xfcr sensible personenbezogene Daten sichergestellt."],t.w)
B.Oj=new A.F(B.j,[u.Z,"Ich habe ein cross-funktionales Team aus 9 Engineering-Studierenden durch den gesamten SDLC gef\xfchrt und gementort und agile Methoden (Scrum) eingef\xfchrt, die die Sprint-Velocity innerhalb der ersten zwei Quartale um 25 % gesteigert haben."],t.w)
B.Nt=new A.F(B.j,["Dec 2024 - Aug 2025","Dez. 2024 \u2013 Aug. 2025"],t.w)
B.NG=new A.F(B.j,[u.cY,"Werkstudent: Full-Stack-Entwickler & Solution Architect \u2013 KI-Patentrecherche-Tool"],t.w)
B.Nv=new A.F(B.j,[u.cV,"Volkswagen Infotainment GmbH, Bochum, Deutschland. Ich habe ein produktives KI-Patentrecherche-Tool konzipiert und ausgeliefert, das inzwischen \xfcber 3 Abteilungen und mehr als 50 interne Anwender skaliert."],t.w)
B.Oh=new A.F(B.j,[u.o,"Ich habe ein produktionsreifes KI-Patentrecherche-Tool (Flutter, Django, ElasticSearch, Docker) eigenverantwortlich konzipiert und ausgeliefert; es wird aktuell in 3 Abteilungen eingesetzt und bedient mehr als 50 interne Mitarbeitende."],t.w)
B.NE=new A.F(B.j,[u.k,"Mit Enterprise Architect habe ich die gesamte Systemlandschaft (UML/SysML) entworfen und dokumentiert, s\xe4mtliche Abh\xe4ngigkeiten zwischen Infrastruktur und Code abgebildet und damit reibungslose DevSecOps-\xdcbergaben sowie Security-Audits erm\xf6glicht."],t.w)
B.Nc=new A.F(B.j,[u.u,"Ich habe eine hybride semantische Suchmaschine (Keyword + Vector Embeddings) mit A/B-getestetem Ranking entwickelt \u2013 mit 25 % h\xf6herer Suchpr\xe4zision und 40 % verk\xfcrzter Time-to-Discovery f\xfcr die Recherchierenden."],t.w)
B.OL=new A.F(B.j,[u.i,"Ich habe umfassende psychologische Usability-Audits und Nutzerinterviews durchgef\xfchrt und einen strategischen Bericht zu User Pain Points und UX-Roadmap verfasst, der mehr als 4 kritische kognitive Belastungspunkte f\xfcr k\xfcnftige Iterationen identifiziert hat."],t.w)
B.OT=new A.F(B.j,["Mar 2023 - Mar 2024","M\xe4r. 2023 \u2013 M\xe4r. 2024"],t.w)
B.OM=new A.F(B.j,[u.cW,"Technical Lead \u2013 Web3-Plattform f\xfcr Umweltschutz (Utopia-Community GbR)"],t.w)
B.OO=new A.F(B.j,[u._,"Ich habe den Aufbau der Web- und App-Plattform der Utopia Community geleitet, deren Fokus auf Umweltschutz und gemeinn\xfctziger Arbeit liegt."],t.w)
B.Pb=new A.F(B.j,[u.bH,"Dazu geh\xf6rte der Entwurf eines eigenen Krypto-Tokens auf der Polygon-Blockchain."],t.w)
B.OD=new A.F(B.j,[u.n,"Ich habe Anforderungen analysiert, Schnittstellen entworfen und einen effizienten Produktionsprozess etabliert."],t.w)
B.Np=new A.F(B.j,[u.G,"Zus\xe4tzlich habe ich den Smart Contract des Krypto-Tokens in Solidity umgesetzt und die Prototyp-App-Plattform mit Flutter und Dart entwickelt."],t.w)
B.Nl=new A.F(B.j,[u.d,"Ich habe den Prototyp auf der KUER.NRW Green-Entrepreneurship-Messe in Gelsenkirchen pr\xe4sentiert. "],t.w)
B.O3=new A.F(B.j,["Dec 2022 - Dec 2023","Dez. 2022 \u2013 Dez. 2023"],t.w)
B.P6=new A.F(B.j,[u.E,"Studentische Hilfskraft \u2013 Institut f\xfcr Roboterforschung"],t.w)
B.Oo=new A.F(B.j,[u.M,"An der Technischen Universit\xe4t Dortmund habe ich am Institut f\xfcr Roboterforschung im Bereich blendfreies Fernlicht mitgewirkt."],t.w)
B.P3=new A.F(B.j,[u.cz,"Dort habe ich erfolgreich ein Steuerungssystem f\xfcr ein physikalisch simuliertes Fahrzeug entwickelt, das in Unreal Engine \xfcber Blueprints einer Spline-Bahn folgt."],t.w)
B.Pd=new A.F(B.j,[u.f,"Eigenst\xe4ndig habe ich ein C++-Skript f\xfcr eine simulierte Fahrzeugkamera erstellt und optimiert, das 2D-Bounding-Boxes f\xfcr Fu\xdfg\xe4nger und Fahrzeuge berechnet und als Trainingsdaten f\xfcr KIs abspeichert."],t.w)
B.NK=new A.F(B.j,[u.O,"Au\xdferdem habe ich eine Variante dieses Skripts entwickelt, die segmentierte Daten aus der Simulation extrahiert und als Trainingsdaten speichert."],t.w)
B.NV=new A.F(B.j,["Nov 2019 - May 2022","Nov. 2019 \u2013 Mai 2022"],t.w)
B.Og=new A.F(B.j,[u.s,"Mitgr\xfcnder & Lead Developer \u2013 Multiplayer-Kartenspiel"],t.w)
B.Ox=new A.F(B.j,[u.K,"Gaming-Startup, Dortmund, Deutschland. Plattform\xfcbergreifendes Kartenspiel mit eigener Rendering-Engine und skalierbarem Serverless-Backend."],t.w)
B.OY=new A.F(B.j,[u.x,"Ich habe eine performante, plattform\xfcbergreifende Kartenspiel-Engine entwickelt, indem ich das Flutter-Framework um eigene Rendering-Logik erweitert habe \u2013 mit 60 FPS auf Android, iOS, Web, Windows, macOS und Linux."],t.w)
B.Ow=new A.F(B.j,[u.F,"Ich habe ein skalierbares Serverless-Backend mit Firebase Cloud Functions und NoSQL (Firestore) konzipiert, das Echtzeit-Spielzust\xe4nde und persistente Nutzerdaten f\xfcr eine potenziell globale Spielerbasis verwaltet."],t.w)
B.Pc=new A.F(B.j,["Sept 2019 - Oct 2019","Sep. 2019 \u2013 Okt. 2019"],t.w)
B.NN=new A.F(B.j,[u.aT,"Praktikant in Maschinen- und Elektrotechnik \u2013 IMA Schelling GmbH"],t.w)
