B.Os=new A.F(B.j,[u.aD,"Dazu geh\xf6rte die Entwicklung und Optimierung elektrischer Steuerungen mit TwinCAT."],t.w)
B.OI=new A.F(B.j,[u.a3,"Ich war an Montage, Installation, Pr\xfcfung, Inspektion und Wartung pneumatischer Systeme beteiligt."],t.w)
B.NI=new A.F(B.j,[u.X,"Zus\xe4tzlich habe ich praktische Erfahrung in der Fertigung verschiedener metallischer Bauteile mit unterschiedlichen Produktionsverfahren gesammelt \u2013 mit Handwerkzeugen sowie an Dreh- und Fr\xe4smaschinen."],t.w)
B.Pf=new A.F(B.j,["Since 2020","Seit 2020"],t.w)
